import{_ as a,c as t,o as r,ag as s}from"./chunks/framework.piE7uVCg.js";const m=JSON.parse('{"title":"Badges","description":"","frontmatter":{},"headers":[],"relativePath":"securite/access/badges.md","filePath":"securite/access/badges.md"}'),i={name:"securite/access/badges.md"};function n(d,e,o,u,l,c){return r(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="badges" tabindex="-1"><a href="./readme.html">Badges</a> <a class="header-anchor" href="#badges" aria-label="Permalink to &quot;[Badges](readme.md)&quot;">​</a></h1><h2 id="iud" tabindex="-1">IUD <a class="header-anchor" href="#iud" aria-label="Permalink to &quot;IUD&quot;">​</a></h2><p>L’UID d’un tag RFID est analogue à l’adresse MAC pour les cartes réseau Ethernet. Le fabricant de puce le grave en usine au moment de la conception du tag. Il lui attribue un numéro à partir d’une base de données. Ce numéro se trouve sur une partie qui n’est pas réinscriptible*, il n’est donc pas modifiable.</p><ul><li>Désormais, il est possible de trouver sur le marché asiatique des tags de type Mifare avec UID modifiables. C’est-à-dire que l’on pourrait y inscrire l’UID d’un tag Mifare existant…</li></ul><h2 id="mifaire" tabindex="-1">Mifaire <a class="header-anchor" href="#mifaire" aria-label="Permalink to &quot;Mifaire&quot;">​</a></h2><p>Chaque carte à puce contient un circuit intégré avec un numéro d’identification permanent unique (UID) gravé pendant le processus de fabrication. Cet UID est souvent appelé le numéro de série de la carte (CSN).<br> Le numéro de série de la carte n’est pas crypté, tout lecteur conforme ISO peut lire le numéro de série de la carte.<br> Le numéro de série de la carte Mifare est donc l’identifiant unique défini dans la norme ISO 14443-3A.</p><p>A titre d’information, les tags Mifare Classic 1K qui sont les plus répandus, contiennent 64 blocs de données. L’UID est stocké sur le premier secteur (le « bloc 0 ») et les 63 suivants sont dédiés au stockage des données.</p>',7)])])}const f=a(i,[["render",n]]);export{m as __pageData,f as default};
